create table dirkspzm32.pzm_abwesenheitsarten (
    aa_id                number(4, 0) not null enable,
    aa_name              varchar2(100 char) not null enable,
    aa_farbe             number(9, 0),
    aa_kurzname          varchar2(20 char),
    lz_id                number(*, 0),
    aa_einheit           varchar2(20 char),
    aa_beantragbar       varchar2(1 char) default 'F' not null enable,
    kennz_urlaub         varchar2(1 char) default 'F' not null enable,
    aa_einflussfaktor    number(3, 0) default 100,
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.pzm_abwesenheitsarten
    add constraint pk_aa_id primary key ( aa_id )
        using index enable;


